const upsertCopilotQuotaDefault = `-- name: UpsertCopilotQuotaDefault :one
INSERT INTO copilot_quotas (user_id)
VALUES ($1)
ON CONFLICT (user_id) DO UPDATE
   SET updated_at = copilot_quotas.updated_at
RETURNING user_id, plan, requests_used, requests_cap, resets_at, models_allowed,
          updated_at
`

// Lazily creates a free-tier quota row on first use. Idempotent: if a row
// already exists, returns it unchanged.
func (q *Queries) UpsertCopilotQuotaDefault(ctx context.Context, userID pgtype.UUID) (CopilotQuota, error) {
	row := q.db.QueryRow(ctx, upsertCopilotQuotaDefault, userID)
	var i CopilotQuota
	err := row.Scan(
		&i.UserID,
		&i.Plan,
		&i.RequestsUsed,
		&i.RequestsCap,
		&i.ResetsAt,
		&i.ModelsAllowed,
		&i.UpdatedAt,
	)
	return i, err
}

const writeCopilotSessionReport = `-- name: WriteCopilotSessionReport :execrows
UPDATE copilot_session_reports
   SET status = 'ready',
       overall_score = $2,
       section_scores = $3,
       weaknesses = $4,
       recommendations = $5,
       links = $6,
       report_markdown = $7,
       report_url = $8,
       analysis = $9,
       title = $10,
       finished_at = now(),
       updated_at = now()
 WHERE session_id = $1
`

type WriteCopilotSessionReportParams struct {
	SessionID       pgtype.UUID
	OverallScore    int32
	SectionScores   []byte
	Weaknesses      []byte
	Recommendations []byte
	Links           []byte
	ReportMarkdown  string
	ReportUrl       string
	Analysis        []byte
	Title           string
}

// Commits a successful analysis. Status jumps to 'ready' regardless of
// prior state — the analyzer owns the transition.
func (q *Queries) WriteCopilotSessionReport(ctx context.Context, arg WriteCopilotSessionReportParams) (int64, error) {
	result, err := q.db.Exec(ctx, writeCopilotSessionReport,
		arg.SessionID,
		arg.OverallScore,
		arg.SectionScores,
		arg.Weaknesses,
		arg.Recommendations,
		arg.Links,
		arg.ReportMarkdown,
		arg.ReportUrl,
		arg.Analysis,
		arg.Title,
	)
	if err != nil {
		return 0, err
	}
	return result.RowsAffected(), nil
}
